import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Marquee from './Marquee'; // Import your Marquee component

function PlayButton() {
  const [nowPlayingData, setNowPlayingData] = useState({
    title: 'Unknown Title',
    artist: 'Unknown Artist',
  });

  const loadNowPlaying = () => {
    axios
      .get('http://your-azuracast-site.example.com/api/nowplaying/station_shortcode')
      .then((response) => {
        // Update the state with the Now Playing data
        setNowPlayingData(response.data.now_playing.song);
      })
      .catch((error) => {
        console.error(error);
      })
      .then(() => {
        clearTimeout(nowPlayingTimeout);
        nowPlayingTimeout = setTimeout(checkNowPlaying, 15000);
      });
  };

  useEffect(() => {
    loadNowPlaying();
    const nowPlayingTimeout = setTimeout(loadNowPlaying, 15000);

    return () => {
      clearTimeout(nowPlayingTimeout);
    };
  }, []);

  return (
    <div>
      <button className="play-button">
        {/* Your play button icon here */}
      </button>
      <audio src="http://172.232.62.146:8000/radio.mp3" />

      {/* Pass the Now Playing data as props to the Marquee component */}
      <Marquee title={nowPlayingData.title} artist={nowPlayingData.artist} />
    </div>
  );
}

export default PlayButton;
